static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // conservative share per-core
static constexpr uint32_t ALIGN_ELEMS = 256;

// UB usage model per inner accumulation step (floats):
//   a_sub: Kt
//   w_sub: Kt
//   mulTmp: Kt
//   sumScalar: 1
// Total ~ 3*Kt + 1 floats (<= UB_BUDGET_BYTES / 4), plus small temporaries for control.
// Choose Kt accordingly. We stream N dimension with tile = 1 for numerical stability simplicity.
// nTile kept small (1) for LSE streaming, but allow >1 if needed; kernel supports nTile=1 fast path.
static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
